#include<bits/stdc++.h>
using namespace std;
bool v[121][121];
int main() {
	int n,num=0;
	cin >> n;
	for (int i = 1; i <= n; i++) {
		int a, b, c, d;
		cin >> a >> b >> c >> d;
		for (int j = a; j < c; j++) {
			for (int k = b; k < d; k++) {
				v[j][k] = 1;
			}
		}
	}
	for (int i = 0; i <= 101; i++) {
		for (int j = 0; j <= 101; j++) {
			if(v[i][j]){
				num++;
			}
		}
	}
	cout<<num;
	return 0;
}
